function lengthOfLongestSubstringKDistinct(s, k) {
    const charCount = new Map();
    let left = 0;
    let maxLength = 0;

    for (let right = 0; right < s.length; ++right) {
        charCount.set(s[right], (charCount.get(s[right]) || 0) + 1);

        while (charCount.size > k) {
            charCount.set(s[left], charCount.get(s[left]) - 1);
            if (charCount.get(s[left]) === 0) {
                charCount.delete(s[left]);
            }
            left++;
        }

        maxLength = Math.max(maxLength, right - left + 1);
    }
    return maxLength;
}
```

    1. Create a hashmap to store character counts within the sliding window.
2. Initialize `left` and `maxLength` to zero.
3. Iterate through the string with a for loop:
    a. Increment the count of the current character in the hashmap.
    b. If there are more than `k` distinct characters in the hashmap, move `left` to the right to shrink the window and update the count in the hashmap (remove the entry if the count is zero).
    c. Update `maxLength` with the length of the current window right - left + 1.
4. Return `maxLength`.

